// Account Migration Helper
// This workflow helps migrate workflows between accounts

const sourceAccount = {
  email: 'balaji.web.design1@gmail.com',
  apiKey: process.env.SOURCE_API_KEY
};

const targetAccount = {
  email: '22034563001@paruluniversity.ac.in',
  apiKey: process.env.TARGET_API_KEY
};

// Prepare migration data
const migrationData = {
  sourceAccount,
  targetAccount,
  timestamp: new Date().toISOString(),
  status: 'started'
};

return [{
  json: migrationData
}];

// Process and clean workflows for import
const workflows = $input.all();
const cleanedWorkflows = [];

for (const workflow of workflows) {
  // Remove source-specific IDs and timestamps
  const cleaned = {
    ...workflow.json,
    id: undefined,
    createdAt: undefined,
    updatedAt: undefined,
    // Update credentials to target account
    nodes: workflow.json.nodes.map(node => ({
      ...node,
      credentials: node.credentials ? {
        ...node.credentials,
        // Map credentials to target account
      } : undefined
    }))
  };

  cleanedWorkflows.push({ json: cleaned });
}

return cleanedWorkflows;
